(* src/packages/stats/predict.ml *)
open Ast

(** predict(df, model) — performs native prediction for a linear model.
    Inspired by tidypredict. *)
(*
--# Linear Model Prediction
--#
--# Calculates predicted values for a linear model object.
--# Supports models generated by lm() or imported via PMML.
--#
--# @name predict
--# @param data :: DataFrame The new data used for prediction.
--# @param model :: Model The linear model object.
--# @return :: Vector The predicted values.
--# @example
--#   model = lm(mpg ~ wt + hp, data: mtcars)
--#   preds = predict(mtcars, model)
--# @family stats
--# @seealso lm
--# @export
*)
let register env =
  Env.add "predict"
    (make_builtin ~name:"predict" 2 (fun args _env ->
      match args with
      | [VDataFrame df; VDict pairs] ->
        (* Extract coefficients and intercept *)
        let coeffs = match List.assoc_opt "coefficients" pairs with
          | Some (VDict c) -> c
          | _ -> []
        in
        
        if coeffs = [] then
          Error.type_error "Function `predict` expects a model with a `coefficients` dictionary."
        else
          let intercept = ref 0.0 in
          let terms = ref [] in
          
          List.iter (fun (name, v) ->
            match v with
            | VFloat f ->
                if name = "(Intercept)" then
                  intercept := f
                else
                  terms := (name, f) :: !terms
            | _ -> ()
          ) coeffs;
          
          let nrows = Arrow_table.num_rows df.arrow_table in
          let out = Array.make nrows 0.0 in
          
          (* Basic vectorized prediction: y = b0 + sum(bi * xi) *)
          for i = 0 to nrows - 1 do
            out.(i) <- !intercept;
          done;
          
          let success = ref true in
          let error_msg = ref "" in
          
          List.iter (fun (name, coef) ->
            if !success then
              match Arrow_table.get_column df.arrow_table name with
              | None ->
                  success := false;
                  error_msg := Printf.sprintf "Column `%s` not found in DataFrame for prediction." name
              | Some col ->
                  for i = 0 to nrows - 1 do
                    match Arrow_table.get_float col i with
                    | Some x -> out.(i) <- out.(i) +. (coef *. x)
                    | None -> out.(i) <- nan (* Propagate NA: missing predictor yields NaN prediction *)
                  done
          ) !terms;
          
          if not !success then Error.make_error KeyError !error_msg
          else VVector (Array.map (fun x -> VFloat x) out)

      | [VDataFrame _; _] ->
          Error.type_error "Function `predict` expects a model (Dict) as second argument."
      | [_; _] ->
          Error.type_error "Function `predict` expects a DataFrame as first argument."
      | _ ->
          Error.make_error ArityError "Function `predict` expects 2 arguments."
    ))
    env
